import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,t as a}from"./chunks/template-generator-advanced.CleIDHrl.js";import{n as o,t as s}from"./chunks/gradle-prompt.DgUqZl-T.js";const c=JSON.parse(`{"title":"Creare un Progetto","description":"Una guida passo per passo su come creare un nuovo progetto per una mod con il generatore di mod modello di Fabric.","frontmatter":{"title":"Creare un Progetto","description":"Una guida passo per passo su come creare un nuovo progetto per una mod con il generatore di mod modello di Fabric.","authors":["Cactooz","IMB11","radstevee"],"files":[]},"headers":[],"relativePath":"it_it/1.21.10/develop/getting-started/creating-a-project.md","filePath":"versions/1.21.10/translated/it_it/develop/getting-started/creating-a-project.md","lastUpdated":1766682904000}`);var l={name:`it_it/1.21.10/develop/getting-started/creating-a-project.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Creare un Progetto <a class="header-anchor" href="#h1" aria-label="Permalink to “Creare un Progetto”">​</a></h1><p>Fabric offre un modo facile per creare un nuovo progetto per una mod attraverso il Generatore di Mod Modello di Fabric - se vuoi, puoi creare un nuovo progetto manualmente usando la repository della mod esempio, dovresti riferirti alla sezione <a href="#creazione-manuale-del-progetto">Creazione Manuale del Progetto</a>.</p><h2 id="generating-a-project" tabindex="-1">Generare un Progetto <a class="header-anchor" href="#generating-a-project" aria-label="Permalink to “Generare un Progetto”">​</a></h2><p>Puoi usare il <a href="https://fabricmc.net/develop/template/" target="_blank" rel="noreferrer">Generatore di Mod Modello di Fabric</a> per generare un nuovo progetto per la tua mod - dovresti compilare i campi richiesti, come il nome della mod, quello del package, e la versione di Minecraft per la quale vuoi sviluppare.</p><p>Il nome del package dovrebbe essere minuscolo, separato da punti, e unico per evitare conflitti con package di altri programmatori. Di solito viene formattato come un domain internet invertito, per esempio <code>com.example.example-mod</code>.</p><p><img src="/assets/develop/getting-started/template-generator.png" alt="Anteprima del generatore" loading="lazy"></p><p>Se avessi intenzione di usare Kotlin, o di usare i mapping ufficiali di Mojang invece dei mapping di Yarn, o volessi aggiungere generatori di dati, puoi selezionare le opzioni appropriate nella sezione <code>Advanced Options</code>.</p><p><img src="/assets/develop/getting-started/template-generator-advanced.png" alt="Sezione Opzioni Avanzate" loading="lazy"></p><p>Una volta che hai compilato i campi richiesti, premi il pulsante <code>Generate</code>, e il generatore creerà un nuovo progetto per te sotto forma di file zip.</p><p>Dovresti estrarre questo file zip a una posizione che scegli tu, e poi aprire la cartella estratta in IntelliJ IDEA:</p><p><img src="/assets/develop/getting-started/open-project.png" alt="Prompt Apri Progetto" loading="lazy"></p><h2 id="importing-the-project" tabindex="-1">Importare il Progetto <a class="header-anchor" href="#importing-the-project" aria-label="Permalink to “Importare il Progetto”">​</a></h2><p>Non appena hai aperto il progetto in IntelliJ IDEA, l&#39;ambiente di sviluppo dovrebbe automaticamente caricare la configurazione Gradle del progetto ed effettuare le operazioni di setup necessarie.</p><p>Se ricevi una notifica riguardo a uno script di build Gradle, dovresti cliccare il pulsante <code>Importa Progetto Gradle</code>:</p><p><img src="/assets/develop/getting-started/gradle-prompt.png" alt="Prompt di Gradle" loading="lazy"></p><p>Quando il progetto sarà importato, dovresti vedere i file del progetto nell&#39;explorer di progetto, e dovresti poter cominciare a sviluppare la tua mod.</p><h2 id="manual-project-creation" tabindex="-1">Creazione Manuale del Progetto <a class="header-anchor" href="#manual-project-creation" aria-label="Permalink to “Creazione Manuale del Progetto”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Ti servirà che <a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a> sia installato per clonare la repository della mod esempio.</p></div><p>Se non puoi usare il Generatore di Mod Modello di Fabric, dovresti creare un nuovo progetto manualmente seguendo questi passaggi.</p><p>Anzitutto, clona la repository della mod esempio tramite Git:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/FabricMC/fabric-example-mod/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mio-progetto-mod</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Questo clonerà la repository in una nuova cartella chiamata <code>mio-progetto-mod</code>.</p><p>Dovresti poi eliminare la cartella <code>.git</code> dalla repository clonata, e poi aprire il progetto in IntelliJ IDEA. Se la cartella <code>.git</code> dovesse non apparire, dovresti attivare la visualizzazione dei file nascosti nel tuo gestore file.</p><p>Quando avrai aperto il progetto in IntelliJ IDEA, esso dovrebbe automaticamente caricare la configurazione Gradle del progetto ed effettuare le operazioni di setup necessarie.</p><p>Di nuovo, come già detto in precedenza, se ricevi una notifica riguardo a uno script di build Gradle, dovresti cliccare il pulsante <code>Importa Progetto Gradle</code>.</p><h3 id="modifying-the-template" tabindex="-1">Modificare il Template <a class="header-anchor" href="#modifying-the-template" aria-label="Permalink to “Modificare il Template”">​</a></h3><p>Una volta che il progetto sarà importato, dovresti modificare i dettagli del progetto per corrispondere a quelli della tua mod:</p><ul><li>Modifica il file <code>gradle.properties</code> del tuo progetto per cambiare le proprietà <code>maven_group</code> e <code>archive_base_name</code> e farle corrispondere con i dettagli della tua mod.</li><li>Modifica il file <code>fabric.mod.json</code> per cambiare le proprietà <code>id</code>, <code>name</code>, e <code>descrizione</code> per farle corrispondere ai dettagli della tua mod.</li><li>Assicurati di aggiornare le versioni di Minecraft, i mapping, il Loader e il Loom - tutte queste possono essere trovate attraverso <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">https://fabricmc.net/develop/</a> - per farle corrispondere alle versioni che vorresti prendere di mira.</li></ul><p>Ovviamente puoi cambiare il nome del package e la classe principale della mod per farli corrispondere ai dettagli della tua mod.</p>`,29)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};